def bm25_topk(query, k=5):
    scores = bm25.get_scores(query.lower().split())
    return list(np.argsort(scores)[::-1][:k])  # doc indices

def vector_topk(query, k=5):
    qv = model.encode(query, normalize_embeddings=True)
    sims = doc_vecs @ qv                        # cosine, normalized
    return list(np.argsort(sims)[::-1][:k])

